            amountGivenScaled18: amountIn,
            balancesScaled18: balances,
            indexIn: RESERVE_TOKEN_INDEX,
            indexOut: PROJECT_TOKEN_INDEX,
            router: address(0),
            userData: ""
        });

        uint256 amountOut = pool.onSwap(params);

        assertTrue(amountOut > 0, "Output should be positive");
    }
}

