import {IVaultErrors} from "@balancer-labs/v3-interfaces/contracts/vault/IVaultErrors.sol";
import {
    HooksConfig,
    LiquidityManagement,
    PoolRoleAccounts,
    SwapKind,
    TokenConfig,
    PoolSwapParams
} from "@balancer-labs/v3-interfaces/contracts/vault/VaultTypes.sol";

import {CastingHelpers} from "@balancer-labs/v3-solidity-utils/contracts/helpers/CastingHelpers.sol";
import {ArrayHelpers} from "@balancer-labs/v3-solidity-utils/contracts/test/ArrayHelpers.sol";
import {FixedPoint} from "@balancer-labs/v3-solidity-utils/contracts/math/FixedPoint.sol";
import {StableMath} from "@balancer-labs/v3-solidity-utils/contracts/math/StableMath.sol";

import {StablePool} from "@balancer-labs/v3-pool-stable/contracts/StablePool.sol";
import {StablePoolFactory} from "@balancer-labs/v3-pool-stable/contracts/StablePoolFactory.sol";
import {
    StablePoolContractsDeployer
} from "@balancer-labs/v3-pool-stable/test/foundry/utils/StablePoolContractsDeployer.sol";

import {BaseVaultTest} from "@balancer-labs/v3-vault/test/foundry/utils/BaseVaultTest.sol";
import {PoolFactoryMock} from "@balancer-labs/v3-vault/contracts/test/PoolFactoryMock.sol";
import {PoolMock} from "@balancer-labs/v3-vault/contracts/test/PoolMock.sol";

import {DirectionalFeeHookExample} from
    "@crane/contracts/protocols/dexes/balancer/v3/hooks/DirectionalFeeHookExample.sol";

/**
 * @title DirectionalFeeHookExampleTest
 * @notice Tests for the DirectionalFeeHookExample contract.
 * @dev Verifies dynamic fee calculation based on pool equilibrium.
 *
 * Key behaviors tested:
 * - Swaps moving toward equilibrium use static fee
 * - Swaps moving away from equilibrium pay higher fees
 * - Fee doubles at max imbalance
 */
contract DirectionalFeeHookExampleTest is StablePoolContractsDeployer, BaseVaultTest {
    using CastingHelpers for address[];
    using FixedPoint for uint256;
    using ArrayHelpers for *;

    uint256 internal daiIdx;
    uint256 internal usdcIdx;

    address internal directionalFeeHook;
    PoolFactoryMock internal poolFactoryMock;

    uint256 internal constant DEFAULT_AMP_FACTOR = 200;
    uint256 internal constant SWAP_FEE_PERCENTAGE = 10e16; // 10%

    function setUp() public override {
        super.setUp();

        (daiIdx, usdcIdx) = getSortedIndexes(address(dai), address(usdc));
        poolFactoryMock = PoolFactoryMock(address(vault.getPoolFactoryMock()));
    }

    function createPoolFactory() internal override returns (address) {
        return address(deployStablePoolFactory(IVault(address(vault)), 365 days, "Factory v1", "Pool v1"));
    }

    function createHook() internal override returns (address) {
        vm.prank(lp);
        directionalFeeHook = address(
            new DirectionalFeeHookExample(IVault(address(vault)), poolFactory)
        );
        vm.label(directionalFeeHook, "Directional Fee Hook");
        return directionalFeeHook;
    }

    function _createPool(
        address[] memory tokens,
        string memory label
    ) internal override returns (address newPool, bytes memory poolArgs) {
        string memory name = "Stable Pool Test";
        string memory symbol = "STABLE-TEST";

        PoolRoleAccounts memory roleAccounts;

        vm.expectEmit(true, true, false, false);
        emit DirectionalFeeHookExample.DirectionalFeeHookExampleRegistered(
            directionalFeeHook,
            poolFactory,
            address(0)
        );

        newPool = address(
            StablePoolFactory(poolFactory).create(
                name,
                symbol,
                vault.buildTokenConfig(tokens.asIERC20()),
                DEFAULT_AMP_FACTOR,
                roleAccounts,
                BASE_MIN_SWAP_FEE,
                poolHooksContract,
                false, // Does not allow donations
                false, // Do not disable unbalanced add/remove liquidity
                ZERO_BYTES32
            )
        );
        vm.label(newPool, label);

        authorizer.grantRole(vault.getActionId(IVaultAdmin.setStaticSwapFeePercentage.selector), admin);
        vm.prank(admin);
        vault.setStaticSwapFeePercentage(newPool, SWAP_FEE_PERCENTAGE);

        poolArgs = abi.encode(
            StablePool.NewPoolParams({
                name: name,
                symbol: symbol,
                amplificationParameter: DEFAULT_AMP_FACTOR,
                version: "Pool v1"
            }),
            vault
        );
    }

    /* ========================================================================== */
    /*                             REGISTRATION TESTS                             */
    /* ========================================================================== */

    function testRegistryWithWrongFactory() public {
        address directionalFeePool = _createPoolToRegister();
        TokenConfig[] memory tokenConfig = vault.buildTokenConfig(
            [address(dai), address(usdc)].toMemoryArray().asIERC20()
        );

        vm.expectRevert(
            abi.encodeWithSelector(
                IVaultErrors.HookRegistrationFailed.selector,
                poolHooksContract,
                directionalFeePool,
                address(poolFactoryMock)
            )
        );
        _registerPoolWithHook(directionalFeePool, tokenConfig);
    }

    function testSuccessfulRegistry() public view {
        HooksConfig memory hooksConfig = vault.getHooksConfig(pool);

        assertEq(hooksConfig.hooksContract, poolHooksContract, "hooksContract is wrong");
        assertTrue(hooksConfig.shouldCallComputeDynamicSwapFee, "shouldCallComputeDynamicSwapFee is false");
    }

    /* ========================================================================== */
    /*                             DYNAMIC FEE TESTS                              */
    /* ========================================================================== */

    function testSwapBalancingPoolFee() public {
        // Make an initial swap to meaningfully unbalance the pool (USDC >> DAI)
        vm.prank(bob);
        router.swapSingleTokenExactIn(pool, usdc, dai, poolInitAmount / 2, 0, MAX_UINT256, false, bytes(""));

        uint256 daiExactAmountIn = poolInitAmount / 10;

        BaseVaultTest.Balances memory balancesBefore = getBalances(lp);

        // Calculate expected amount out (amount out without fees)
        uint256 poolInvariant = StableMath.computeInvariant(
            DEFAULT_AMP_FACTOR * StableMath.AMP_PRECISION,
            balancesBefore.poolTokens
        );
        uint256 swapFeeAmount = daiExactAmountIn.mulUp(SWAP_FEE_PERCENTAGE);
        uint256 expectedAmountOut = StableMath.computeOutGivenExactIn(
            DEFAULT_AMP_FACTOR * StableMath.AMP_PRECISION,
            balancesBefore.poolTokens,
            daiIdx,
            usdcIdx,
            daiExactAmountIn - swapFeeAmount,
            poolInvariant
        );

        // Swap DAI for USDC, bringing the pool closer to equilibrium
        vm.prank(bob);
        router.swapSingleTokenExactIn(pool, dai, usdc, daiExactAmountIn, 0, MAX_UINT256, false, bytes(""));

        BaseVaultTest.Balances memory balancesAfter = getBalances(lp);

        uint256 actualAmountOut = balancesAfter.bobTokens[usdcIdx] - balancesBefore.bobTokens[usdcIdx];

        // When balancing, fee should equal static fee
        assertEq(expectedAmountOut, actualAmountOut, "Amount out is wrong");

        // Check Bob's balances
        assertEq(
            balancesBefore.bobTokens[daiIdx] - balancesAfter.bobTokens[daiIdx],
            daiExactAmountIn,
            "Bob DAI balance is wrong"
        );
    }

    function testSwapUnbalancingPoolFee() public {
        // Swap to take the pool out of equilibrium
        uint256 daiExactAmountIn = poolInitAmount / 2;

        BaseVaultTest.Balances memory balancesBefore = getBalances(lp);
        uint256[] memory balancesScaled18 = balancesBefore.poolTokens;

        uint256 poolInvariant = StableMath.computeInvariant(
            DEFAULT_AMP_FACTOR * StableMath.AMP_PRECISION,
            balancesScaled18
        );

        // Call the dynamic fee hook to get expected fee
        vm.prank(address(vault));
        (, uint256 expectedSwapFeePercentage) = DirectionalFeeHookExample(poolHooksContract)
            .onComputeDynamicSwapFeePercentage(
                PoolSwapParams({
                    kind: SwapKind.EXACT_IN,
                    amountGivenScaled18: daiExactAmountIn,
                    balancesScaled18: balancesScaled18,
                    indexIn: daiIdx,
                    indexOut: usdcIdx,
                    router: address(router),
                    userData: bytes("")
                }),
                pool,
                SWAP_FEE_PERCENTAGE
            );

        // Fee should be higher than static when unbalancing
        assertTrue(
            expectedSwapFeePercentage > SWAP_FEE_PERCENTAGE,
            "Dynamic fee should be higher than static fee when unbalancing"
        );

        // Calculate expected output with increased fee
        uint256 swapFeeAmount = daiExactAmountIn.mulUp(expectedSwapFeePercentage);
        uint256 expectedAmountOut = StableMath.computeOutGivenExactIn(
            DEFAULT_AMP_FACTOR * StableMath.AMP_PRECISION,
            balancesScaled18,
            daiIdx,
            usdcIdx,
            daiExactAmountIn - swapFeeAmount,
            poolInvariant
        );

        // Execute swap
        vm.prank(bob);
        router.swapSingleTokenExactIn(pool, dai, usdc, daiExactAmountIn, 0, MAX_UINT256, false, bytes(""));

        BaseVaultTest.Balances memory balancesAfter = getBalances(lp);

        uint256 actualAmountOut = balancesAfter.bobTokens[usdcIdx] - balancesBefore.bobTokens[usdcIdx];

        assertEq(expectedAmountOut, actualAmountOut, "Amount out with dynamic fee is wrong");
    }

    function testSwapExactOutBalancing() public {
        // First unbalance the pool
        vm.prank(bob);
        router.swapSingleTokenExactIn(pool, usdc, dai, poolInitAmount / 2, 0, MAX_UINT256, false, bytes(""));

        BaseVaultTest.Balances memory balancesBefore = getBalances(lp);

        uint256 usdcExactAmountOut = poolInitAmount / 10;

        // Swap DAI for exact USDC out, bringing pool closer to equilibrium
        vm.prank(bob);
        router.swapSingleTokenExactOut(
            pool,
            dai,
            usdc,
            usdcExactAmountOut,
            type(uint256).max,
            MAX_UINT256,
            false,
            bytes("")
        );

        BaseVaultTest.Balances memory balancesAfter = getBalances(lp);

        // Verify Bob received the exact amount requested
        assertEq(
            balancesAfter.bobTokens[usdcIdx] - balancesBefore.bobTokens[usdcIdx],
            usdcExactAmountOut,
            "Bob should receive exact USDC amount"
        );
    }

    /* ========================================================================== */
    /*                              HELPER FUNCTIONS                              */
    /* ========================================================================== */

    function _createPoolToRegister() private returns (address newPool) {
        newPool = address(deployPoolMock(IVault(address(vault)), "Stable Pool", "STABLE"));
        vm.label(newPool, "Directional Fee Pool");
    }

    function _registerPoolWithHook(
        address feePool,
        TokenConfig[] memory tokenConfig
    ) private {
        PoolRoleAccounts memory roleAccounts;
        LiquidityManagement memory liquidityManagement;

        poolFactoryMock.registerPool(
            feePool,
            tokenConfig,
            roleAccounts,
            poolHooksContract,
            liquidityManagement
        );
    }
}

